class Team {
  constructor(team = []) { this.team = team; }
  pack() { return JSON.stringify(this.team); }
  export() {
    return this.team.map(set => {
      const lines = [];
      const name = set.name || set.species || 'Pokemon';
      lines.push(`${name}${set.item ? ` @ ${set.item}` : ''}`);
      lines.push(`Ability: ${set.ability || ''}`);
      if (set.level) lines.push(`Level: ${set.level}`);
      if (set.shiny) lines.push('Shiny: Yes');
      if (set.teraType) lines.push(`Tera Type: ${set.teraType}`);
      if (set.evsh) lines.push(`EVs: ${JSON.stringify(set.evs)}`);
      if (set.nature) lines.push(`${set.nature} Nature`);
      for (const move of set.moves || []) lines.push(`- ${move}`);
      return lines.join('\n');
    }).join('\n\n');
  }
}
const Sets = {
  exportSet(set) { return new Team([set]).export(); },
};
const Teams = {
  unpackTeam(buf) {
    try { return {team: JSON.parse(buf)}; } catch { return null; }
  },
  importTeam(buf) {
    try { return {team: JSON.parse(buf)}; } catch { return null; }
  },
};
module.exports = {Team, Sets, Teams};
